471	pub fn parse_artifact_section(mut bytes: &[u8]) -> Result<Vec<ArtifactBundle<'_>>, ArtifactError> {
472	    let mut bundles = Vec::new();
473	    while !bytes.is_empty() {
474	        if bytes.iter().all(|byte| *byte == 0) {
475	            break;
476	        }
477	        let total_len = artifact_blob_total_len(bytes)?;
478	        let (blob, rest) = bytes.split_at(total_len);
479	        bundles.push(parse_artifact_blob(blob)?);
480	        bytes = rest;
481	    }
482	    Ok(bundles)
483	}
484	
485	pub fn parse_artifact_blob(bytes: &[u8]) -> Result<ArtifactBundle<'_>, ArtifactError> {
486	    require_len(bytes, HEADER_BYTES, "header")?;
487	    if bytes[0..8] != ARTIFACT_MAGIC {
488	        return Err(ArtifactError::BadMagic);
489	    }
490	    let version = read_u16(bytes, 8)?;
491	    if !matches!(version, LEGACY_ARTIFACT_VERSION | ARTIFACT_VERSION) {
492	        return Err(ArtifactError::UnsupportedVersion(version));
493	    }
494	    let header_len = read_u16(bytes, 10)? as usize;
495	    if header_len != HEADER_BYTES {
496	        return Err(ArtifactError::Malformed(format!(
497	            "unsupported embedded artifact header length {header_len}"
498	        )));
499	    }
500	    let total_len = read_u32(bytes, 12)? as usize;
501	    if total_len < HEADER_BYTES {
502	        return Err(ArtifactError::Malformed(format!(
503	            "embedded artifact length {total_len} is smaller than the header"
504	        )));
505	    }
506	    if total_len > bytes.len() {
507	        return Err(ArtifactError::Truncated("blob"));
508	    }
509	    let bytes = &bytes[..total_len];
510	    let name_len = read_u16(bytes, 16)? as usize;
511	    let target_len = read_u16(bytes, 18)? as usize;
512	    let payload_count = read_u16(bytes, 20)? as usize;
513	    let entry_count = read_u16(bytes, 22)? as usize;
514	    let compile_options = if version == LEGACY_ARTIFACT_VERSION {
515	        ArtifactCompileOptions::new()
516	    } else {
517	        ArtifactCompileOptions::from_bits(read_u64(bytes, 24)?)?
518	    };
519	
520	    let mut cursor = HEADER_BYTES;
521	    let name = read_str(bytes, cursor, name_len, "bundle name")?;
522	    cursor += name_len;
523	    let target = read_str(bytes, cursor, target_len, "target")?;
524	    cursor += target_len;
525	
526	    let payload_records = cursor;
527	    cursor = cursor
528	        .checked_add(payload_count * PAYLOAD_RECORD_BYTES)
529	        .ok_or(ArtifactError::TooLarge("payload records"))?;
530	    require_len(bytes, cursor, "payload records")?;
531	    let entry_records = cursor;
532	    cursor = cursor
533	        .checked_add(entry_count * ENTRY_RECORD_BYTES)
534	        .ok_or(ArtifactError::TooLarge("entry records"))?;
535	    require_len(bytes, cursor, "entry records")?;
536	
537	    let mut payloads = Vec::with_capacity(payload_count);
538	    for index in 0..payload_count {
539	        let record = payload_records + index * PAYLOAD_RECORD_BYTES;
540	        let kind_raw = read_u16(bytes, record)?;
541	        let kind = ArtifactPayloadKind::from_u16(kind_raw)
542	            .ok_or(ArtifactError::UnsupportedPayloadKind(kind_raw))?;
543	        let data_offset = read_u32(bytes, record + 4)? as usize;
544	        let data_len = read_u32(bytes, record + 8)? as usize;
545	        let name_offset = read_u32(bytes, record + 12)? as usize;
546	        let name_len = read_u16(bytes, record + 16)? as usize;
547	        let name = read_str(bytes, name_offset, name_len, "payload name")?;
548	        let data = read_slice(bytes, data_offset, data_len, "payload data")?;
549	        payloads.push(ArtifactPayload {
550	            kind,
551	            name,
552	            bytes: data,
553	        });
554	    }
555	
556	    let mut entries = Vec::with_capacity(entry_count);
557	    for index in 0..entry_count {
558	        let record = entry_records + index * ENTRY_RECORD_BYTES;
559	        let kind_raw = read_u16(bytes, record)?;
560	        let kind = ArtifactEntryKind::from_u16(kind_raw)
561	            .ok_or(ArtifactError::UnsupportedEntryKind(kind_raw))?;
562	        let flags = read_u16(bytes, record + 2)?;
563	        let metadata = if flags & 1 != 0 {
564	            Some(read_u64(bytes, record + 4)?)
565	        } else {
566	            None
567	        };
568	        let symbol_offset = read_u32(bytes, record + 12)? as usize;
569	        let symbol_len = read_u16(bytes, record + 16)? as usize;
570	        let symbol = read_str(bytes, symbol_offset, symbol_len, "entry symbol")?;
571	        entries.push(ArtifactEntry {
572	            symbol,
573	            kind,
574	            metadata,
575	        });
576	    }
577	
578	    Ok(ArtifactBundle {
579	        name,
580	        target,
581	        compile_options,
582	        payloads,
583	        entries,
584	    })
585	}
