684	/// Build a host object that only defines an artifact link-anchor symbol.
685	///
686	/// The CUDA backend uses this when an owner filter deliberately suppresses a
687	/// crate's device artifact. Older `#[cuda_module]` expansions can still
688	/// contain the legacy anchor reference, so the linker needs a matching weak
689	/// definition even though no `.oxart` section should be embedded. Keeping the
690	/// placeholder in a separate section means artifact discovery correctly sees
691	/// no device bundle.
692	#[cfg(feature = "object-write")]
693	pub fn build_host_anchor_object_for_target(
694	    target: &str,
695	    anchor_symbol: &str,
696	) -> Result<Vec<u8>, ArtifactError> {
697	    if anchor_symbol.is_empty() {
698	        return Err(ArtifactError::Malformed(
699	            "embedded artifact anchor symbol is empty".to_string(),
700	        ));
701	    }
702	
703	    build_host_object_with_section(
704	        ARTIFACT_ANCHOR_SECTION_NAME,
705	        &[0],
706	        target,
707	        &[(anchor_symbol, true)],
708	    )
709	}
