711	#[cfg(feature = "object-write")]
712	fn build_host_object_with_section(
713	    section_name: &str,
714	    section_data: &[u8],
715	    target: &str,
716	    anchor_symbols: &[(&str, bool)],
717	) -> Result<Vec<u8>, ArtifactError> {
718	    use object::write::{Object, Symbol, SymbolSection};
719	    use object::{SectionFlags, SectionKind, SymbolFlags, SymbolKind, SymbolScope};
720	
721	    let target = HostObjectTarget::parse(target)?;
722	    let mut object = Object::new(target.format, target.architecture, target.endianness);
723	    let section_id = object.add_section(
724	        Vec::new(),
725	        section_name.as_bytes().to_vec(),
726	        SectionKind::Data,
727	    );
728	    let section = object.section_mut(section_id);
729	    section.set_data(section_data.to_vec(), 8);
730	    section.flags = SectionFlags::Elf {
731	        sh_flags: elf::SHF_ALLOC | elf::SHF_GNU_RETAIN,
732	    };
733	
734	    for (anchor_symbol, weak) in anchor_symbols {
735	        // Global binding so the symbol can satisfy undefined references
736	        // from other objects (that is what triggers archive extraction);
737	        // `Linkage` scope so it stays hidden and never leaks into the
738	        // dynamic symbol table of the final binary.
739	        object.add_symbol(Symbol {
740	            name: anchor_symbol.as_bytes().to_vec(),
741	            value: 0,
742	            size: 0,
743	            kind: SymbolKind::Data,
744	            scope: SymbolScope::Linkage,
745	            weak: *weak,
746	            section: SymbolSection::Section(section_id),
747	            flags: SymbolFlags::None,
748	        });
749	    }
750	
751	    object
752	        .write()
753	        .map_err(|e| ArtifactError::Object(e.to_string()))
754	}
