799	fn validate_spec(spec: &ArtifactBundleSpec<'_>) -> Result<(), ArtifactError> {
800	    if spec.name.is_empty() {
801	        return Err(ArtifactError::EmptyBundleName);
802	    }
803	    if spec.target.is_empty() {
804	        return Err(ArtifactError::EmptyTarget);
805	    }
806	    if spec.payloads.is_empty() {
807	        return Err(ArtifactError::EmptyPayload);
808	    }
809	    for payload in &spec.payloads {
810	        if payload.name.is_empty() {
811	            return Err(ArtifactError::EmptyPayloadName);
812	        }
813	        if payload.bytes.is_empty() {
814	            return Err(ArtifactError::EmptyPayload);
815	        }
816	    }
817	    for entry in &spec.entries {
818	        if entry.symbol.is_empty() {
819	            return Err(ArtifactError::EmptyEntrySymbol);
820	        }
821	    }
822	    Ok(())
823	}
