833	fn push_bytes(out: &mut Vec<u8>, bytes: &[u8]) {
834	    out.extend_from_slice(bytes);
835	}
836	
837	fn align_vec(out: &mut Vec<u8>, alignment: usize) {
838	    let rem = out.len() % alignment;
839	    if rem != 0 {
840	        out.resize(out.len() + alignment - rem, 0);
841	    }
842	}
