99	        let lane = tid % 32;
100	        let warp_id = tid / 32;
101	
102	        // Each thread loads a value
103	        let value = unsafe { *input.add(tid as usize) };
104	
105	        // Warp-level reduction using CUB
106	        let warp_sum = unsafe { cub_warp_reduce_sum_f32(value) };
107	
108	        // Lane 0 of each warp writes result
109	        if lane == 0 {
110	            unsafe {
111	                *output.add(warp_id as usize) = warp_sum;
112	            }
113	        }
114	    }
115	
116	    /// Test kernel with multiple attribute combinations
117	    #[kernel]
118	    pub fn test_mixed_attrs(a: *const f32, b: *const f32, output: *mut f32, n: i32) {
119	        let tid = cuda_device::thread::threadIdx_x() as usize;
120	
121	        // Use readonly function
122	        let dot = unsafe { dot_product(a, b, n) };
123	
124	        // Use pure function
125	        let rsqrt = unsafe { fast_rsqrt(dot) };
126	
127	        // Use convergent function
128	        let ballot = unsafe { warp_ballot(if rsqrt > 0.5 { 1 } else { 0 }) };
129	        unsafe {
130	            *output.add(tid) = rsqrt * (ballot as f32);
131	        }
132	    }
