134	    /// Test dynamic shared memory alignment with extern functions.
135	    ///
136	    /// This kernel tests what happens when:
137	    /// - Rust uses DynamicSharedArray with 16B alignment (default)
138	    /// - Extern C++ function expects 128B alignment (TmaAligned128)
139	    ///
140	    /// The question: Does the linker take the max alignment (128B)?
141	    /// Or does Rust's 16B declaration "win" and cause misalignment?
142	    ///
143	    /// Scenario A (16B only from Rust side):
144	    /// ```
145	    /// .extern .shared .align 16 .b8 __dynamic_smem_test_smem_alignment_cross_module[];
146	    /// ```
147	    ///
148	    /// Scenario B (if linker merges correctly):
149	    /// ```
150	    /// .extern .shared .align 128 .b8 ...;  // max(16, 128) = 128
151	    /// ```
152	    #[kernel]
153	    pub fn test_smem_alignment_cross_module(output: *mut u64) {
154	        let tid = cuda_device::thread::threadIdx_x();
155	
156	        // Rust side: request 16B alignment (deliberately low)
157	        let rust_smem: *mut f32 = DynamicSharedArray::<f32, 16>::get();
158	
159	        // Get addresses from both Rust and extern C++ perspectives
160	        let rust_addr = rust_smem as u64;
161	        let extern_addr = unsafe { smem_get_base_addr() };
162	
163	        if tid == 0 {
164	            gpu_printf!("[DEBUG] Rust smem addr: {:x}\n", rust_addr);
165	            gpu_printf!("[DEBUG] Extern smem addr: {:x}\n", extern_addr);
166	            gpu_printf!("[DEBUG] Before write: rust[0] = {:.2f}\n", unsafe {
167	                *rust_smem
168	            });
169	        }
170	
171	        // Write via extern function (expects 128B alignment internally)
172	        if tid == 0 {
173	            unsafe {
174	                gpu_printf!("[DEBUG] Writing 42.0 via extern function...\n");
175	                smem_write_aligned_128(0, 42.0);
176	                gpu_printf!("[DEBUG] Write done\n");
177	            }
178	        }
179	
180	        cuda_device::sync_threads();
181	
182	        // Read back via Rust pointer
183	        let value_via_rust = unsafe { *rust_smem };
184	
185	        // Read back via extern function
186	        let value_via_extern = unsafe { smem_read_aligned_128(0) };
187	
188	        if tid == 0 {
189	            // Use pointer cast to get actual bits (to_bits() might not work on GPU)
190	            let rust_bits: u32 = unsafe { *((&value_via_rust) as *const f32 as *const u32) };
191	            let extern_bits: u32 = unsafe { *((&value_via_extern) as *const f32 as *const u32) };
192	
193	            gpu_printf!("[DEBUG] After write:\n");
194	            gpu_printf!(
195	                "[DEBUG]   Rust read:   {:.2f} (bits via cast: {:x})\n",
196	                value_via_rust,
197	                rust_bits
198	            );
199	            gpu_printf!(
200	                "[DEBUG]   Extern read: {:.2f} (bits via cast: {:x})\n",
201	                value_via_extern,
202	                extern_bits
203	            );
204	            gpu_printf!(
205	                "[DEBUG]   to_bits():   rust={:x}, extern={:x}\n",
206	                value_via_rust.to_bits(),
207	                value_via_extern.to_bits()
208	            );
209	
210	            // Also try direct write via Rust and read via extern
211	            gpu_printf!("[DEBUG] Writing 99.0 via Rust pointer...\n");
212	            unsafe { *rust_smem = 99.0 };
213	            let extern_read_after_rust_write = unsafe { smem_read_aligned_128(0) };
214	            gpu_printf!(
215	                "[DEBUG]   Extern read after Rust write: {:.2f}\n",
216	                extern_read_after_rust_write
217	            );
218	
219	            // Output results using pointer cast for bits
220	            unsafe {
221	                *output.add(0) = rust_addr;
222	                *output.add(1) = extern_addr;
223	                *output.add(2) = rust_bits as u64;
224	                *output.add(3) = extern_bits as u64;
225	                *output.add(4) = rust_addr % 128;
226	                *output.add(5) = extern_addr % 128;
227	            }
228	
229	            gpu_printf!(
230	                "[DEBUG] Output written: bits[2]={:x}, bits[3]={:x}\n",
231	                rust_bits,
232	                extern_bits
233	            );
234	        }
235	    }
236	}
