269	/// Runs a shell command in the specified directory.
270	///
271	/// # Arguments
272	/// * `cmd` - The command to run
273	/// * `args` - Arguments to pass to the command
274	/// * `cwd` - Working directory for the command
275	///
276	/// # Returns
277	/// `Ok(())` on success, `Err(message)` on failure
278	fn run_command(cmd: &str, args: &[&str], cwd: &Path) -> Result<(), String> {
279	    let status = Command::new(cmd)
280	        .args(args)
281	        .current_dir(cwd)
282	        .status()
283	        .map_err(|e| format!("Failed to run {}: {}", cmd, e))?;
284	
285	    if status.success() {
286	        Ok(())
287	    } else {
288	        Err(format!("{} failed with exit code {:?}", cmd, status.code()))
289	    }
290	}
