292	/// Checks if a target file needs to be rebuilt based on source file timestamps.
293	///
294	/// Returns `true` if:
295	/// - The target file doesn't exist, OR
296	/// - Any source file is newer than the target
297	fn file_needs_rebuild(target: &Path, sources: &[&Path]) -> bool {
298	    if !target.exists() {
299	        return true;
300	    }
301	    let target_time = target.metadata().and_then(|m| m.modified()).ok();
302	    for src in sources {
303	        if let Ok(src_time) = src.metadata().and_then(|m| m.modified())
304	            && target_time.map(|t| src_time > t).unwrap_or(true)
305	        {
306	            return true;
307	        }
308	    }
309	    false
310	}
