320	    let link_source = tools_dir.join("link_ltoir.c");
321	    let options_header = tools_dir.join("compile_options.h");
322	    let build_script = tools_dir.join("build_tools.sh");
323	
324	    let compile_sources = [
325	        compile_source.as_path(),
