346	/// Builds external CUDA C++ files to LTOIR if sources have changed or the
347	/// cached LTOIR was built for a different architecture.
348	///
349	/// Compiles `extern-libs/*.cu` to LTOIR using nvcc with `-dc -dlto` flags.
350	///
351	/// ## Arch stamping
352	///
353	/// Plain mtime-based caching is not enough: nvJitLink rejects linking an
354	/// LTOIR built for arch `X` into a cubin targeted at arch `Y` (it errors with
355	/// `ARCH_MISMATCH`). When the user switches `--arch`, the cached `.ltoir`
356	/// from a prior build is newer than the `.cu` but was built for the wrong
357	/// arch. We side-step that by writing a `.ltoir_arch` stamp next to the
358	/// LTOIR files; a mismatch forces a rebuild.
359	fn build_external_ltoir(example_dir: &Path) -> Result<(), String> {
360	    let extern_libs_dir = example_dir.join("extern-libs");
361	    let external_ltoir = extern_libs_dir.join("external_device_funcs.ltoir");
362	    let cccl_ltoir = extern_libs_dir.join("cccl_wrappers.ltoir");
363	    let external_cu = extern_libs_dir.join("external_device_funcs.cu");
364	    let cccl_cu = extern_libs_dir.join("cccl_wrappers.cu");
365	    let arch_stamp = extern_libs_dir.join(".ltoir_arch");
366	
367	    let arch = get_arch();
368	    let stamp_mismatch = std::fs::read_to_string(&arch_stamp)
369	        .map(|s| s.trim() != arch)
370	        .unwrap_or(true);
371	    let needs_rebuild = stamp_mismatch
372	        || file_needs_rebuild(&external_ltoir, &[&external_cu])
373	        || file_needs_rebuild(&cccl_ltoir, &[&cccl_cu]);
374	
375	    if !needs_rebuild {
376	        return Ok(());
377	    }
378	
379	    if stamp_mismatch && external_ltoir.exists() {
380	        println!(
381	            "=== Rebuilding external LTOIR (arch changed → {}) ===",
382	            arch
383	        );
384	    } else {
385	        println!("=== Building external LTOIR ({}) ===", arch);
386	    }
387	    run_command("./build_ltoir.sh", &[arch], &extern_libs_dir)?;
388	    std::fs::write(&arch_stamp, arch).map_err(|e| format!("Failed to write arch stamp: {}", e))?;
389	    println!("  ✓ External LTOIR built\n");
390	    Ok(())
391	}
