430	/// Links all LTOIR files into a single cubin using nvJitLink.
431	///
432	/// Combines:
433	/// - `device_ffi_test.ltoir` (cuda-oxide kernels)
434	/// - `extern-libs/external_device_funcs.ltoir` (simple device functions)
435	/// - `extern-libs/cccl_wrappers.ltoir` (CUB wrappers)
436	///
437	/// Returns the path to the merged cubin on success.
438	fn link_ltoir(example_dir: &Path) -> Result<std::path::PathBuf, String> {
439	    let tools_dir = example_dir.join("tools");
440	    let extern_libs_dir = example_dir.join("extern-libs");
441	    let cubin_file = example_dir.join("merged.cubin");
442	    let cuda_oxide_ltoir = example_dir.join("device_ffi_test.ltoir");
443	    let external_ltoir = extern_libs_dir.join("external_device_funcs.ltoir");
444	    let cccl_ltoir = extern_libs_dir.join("cccl_wrappers.ltoir");
445	
446	    let sources = [&cuda_oxide_ltoir, &external_ltoir, &cccl_ltoir];
447	    let source_refs: Vec<&Path> = sources.iter().map(|p| p.as_path()).collect();
448	
449	    if !file_needs_rebuild(&cubin_file, &source_refs) {
450	        return Ok(cubin_file);
451	    }
452	
453	    println!("=== Linking LTOIR files ===");
454	    run_command(
455	        "./link_ltoir",
456	        &[
457	            &format!("-arch={}", get_arch()),
458	            "-o",
459	            cubin_file.to_str().unwrap(),
460	            cuda_oxide_ltoir.to_str().unwrap(),
461	            external_ltoir.to_str().unwrap(),
462	            cccl_ltoir.to_str().unwrap(),
463	        ],
464	        &tools_dir,
465	    )?;
466	    println!("  ✓ LTOIR linked to cubin\n");
467	    Ok(cubin_file)
468	}
