470	/// Runs the complete build pipeline.
471	///
472	/// 1. Builds tools (if needed)
473	/// 2. Builds external LTOIR (if sources changed)
474	/// 3. Compiles cuda-oxide LLVM IR to LTOIR
475	/// 4. Links all LTOIR to cubin
476	///
477	/// Returns the path to the final cubin on success.
478	fn build_pipeline() -> Result<std::path::PathBuf, String> {
479	    let example_dir = get_example_dir();
480	
481	    build_tools(&example_dir)?;
482	    build_external_ltoir(&example_dir)?;
483	    compile_cuda_oxide_ltoir(&example_dir)?;
484	    link_ltoir(&example_dir)
485	}
