558	/// Test 1: Simple device function calls (magnitude_squared, simple_add, warp_reduce_sum)
559	///
560	/// Each warp computes: sum of (x² + y² + 1) for threads 0-31
561	/// where x = threadIdx and y = threadIdx + 1
562	fn test_simple_device_funcs_runner(
563	    ctx: &Arc<CudaContext>,
564	    module: &kernels::LoadedModule,
565	    passed: &mut i32,
566	    failed: &mut i32,
567	) {
568	    println!("--- Test 1: test_simple_device_funcs ---");
569	    println!("    Functions: magnitude_squared, simple_add, warp_reduce_sum");
570	
571	    let n = 256usize;
572	    let warps = n / 32;
573	
574	    let stream = ctx.default_stream();
575	    let d_output = DeviceBuffer::<f32>::zeroed(&stream, warps).unwrap();
576	
577	    let config = LaunchConfig {
578	        grid_dim: (1, 1, 1),
579	        block_dim: (n as u32, 1, 1),
580	        shared_mem_bytes: 0,
581	    };
582	
583	    // SAFETY: launch shape/resources match the kernel; buffers cover its accesses.
584	    unsafe {
585	        module.test_simple_device_funcs(
586	            (stream).as_ref(),
587	            config,
588	            d_output.cu_deviceptr() as *mut f32,
589	        )
590	    }
591	    .expect("Kernel launch failed");
592	
593	    let h_output = d_output.to_host_vec(&stream).unwrap();
594	
595	    // Verify: each warp computes sum of (x² + y² + 1) for its threads
596	    let mut errors = 0;
597	    for warp in 0..warps {
598	        let base_tid = warp * 32;
599	        let mut expected = 0.0f32;
600	        for lane in 0..32 {
601	            let tid = base_tid + lane;
602	            let x = tid as f32;
603	            let y = (tid + 1) as f32;
604	            expected += x * x + y * y + 1.0;
605	        }
606	        if (h_output[warp] - expected).abs() > 1.0 {
607	            errors += 1;
608	        }
609	    }
610	
611	    if errors == 0 {
612	        println!("    ✓ PASSED");
613	        *passed += 1;
614	    } else {
615	        println!("    ✗ FAILED ({} errors)", errors);
616	        *failed += 1;
617	    }
618	}
