681	/// - `warp_ballot` - warp-level ballot
682	///
683	/// Verifies outputs are finite (not NaN/Inf).
684	fn test_mixed_attrs_runner(
685	    ctx: &Arc<CudaContext>,
686	    module: &kernels::LoadedModule,
687	    passed: &mut i32,
688	    failed: &mut i32,
689	) {
690	    println!("--- Test 3: test_mixed_attrs ---");
691	    println!("    Functions: dot_product, fast_rsqrt, warp_ballot");
692	
693	    let n = 32usize;
694	    let vec_size = 4i32;
695	
696	    let stream = ctx.default_stream();
697	    let h_a = vec![1.0f32, 2.0, 3.0, 4.0];
698	    let h_b = vec![1.0f32, 1.0, 1.0, 1.0];
699	
700	    let d_a = DeviceBuffer::from_host(&stream, &h_a).unwrap();
701	    let d_b = DeviceBuffer::from_host(&stream, &h_b).unwrap();
702	    let d_output = DeviceBuffer::<f32>::zeroed(&stream, n).unwrap();
703	
704	    let config = LaunchConfig {
705	        grid_dim: (1, 1, 1),
706	        block_dim: (n as u32, 1, 1),
707	        shared_mem_bytes: 0,
708	    };
709	
710	    // SAFETY: launch shape/resources match the kernel; buffers cover its accesses.
711	    unsafe {
712	        module.test_mixed_attrs(
713	            (stream).as_ref(),
714	            config,
715	            d_a.cu_deviceptr() as *const f32,
716	            d_b.cu_deviceptr() as *const f32,
717	            d_output.cu_deviceptr() as *mut f32,
718	            vec_size,
719	        )
720	    }
721	    .expect("Kernel launch failed");
722	
723	    let h_output = d_output.to_host_vec(&stream).unwrap();
724	
725	    // Basic validation: outputs should be finite
726	    let valid = h_output.iter().all(|v| v.is_finite());
727	
728	    if valid {
729	        println!("    ✓ PASSED (outputs are finite)");
730	        *passed += 1;
731	    } else {
732	        println!("    ✗ FAILED (invalid outputs)");
733	        *failed += 1;
734	    }
735	}
736	
737	/// Test 4: Cross-module dynamic shared memory alignment
738	///
739	/// Tests alignment behavior when:
740	/// - Rust declares DynamicSharedArray with 16B alignment
741	/// - Extern C++ function internally expects 128B alignment
742	///
743	/// This verifies whether the linker takes max(16, 128) = 128.
744	fn test_smem_alignment_cross_module_runner(
745	    ctx: &Arc<CudaContext>,
746	    module: &kernels::LoadedModule,
747	    passed: &mut i32,
748	    failed: &mut i32,
749	) {
750	    println!("--- Test 4: test_smem_alignment_cross_module ---");
751	    println!("    Testing: Rust (16B align) + Extern C++ (128B align)");
752	
753	    let stream = ctx.default_stream();
754	    let d_output = DeviceBuffer::<u64>::zeroed(&stream, 6).unwrap();
755	
756	    let config = LaunchConfig {
757	        grid_dim: (1, 1, 1),
758	        block_dim: (32, 1, 1),
759	        shared_mem_bytes: 256, // Enough for the test
760	    };
761	
762	    // SAFETY: launch shape/resources match the kernel; buffers cover its accesses.
763	    unsafe {
764	        module.test_smem_alignment_cross_module(
765	            (stream).as_ref(),
766	            config,
767	            d_output.cu_deviceptr() as *mut u64,
768	        )
769	    }
770	    .expect("Kernel launch failed");
771	
772	    // Synchronize to flush printf output
773	    stream.synchronize().expect("Sync failed");
774	
775	    let h_output = d_output.to_host_vec(&stream).unwrap();
776	
777	    let rust_addr = h_output[0];
778	    let extern_addr = h_output[1];
779	    let value_rust_bits = h_output[2] as u32;
780	    let value_extern_bits = h_output[3] as u32;
781	    let rust_align_mod = h_output[4];
782	    let extern_align_mod = h_output[5];
783	
784	    let value_rust = f32::from_bits(value_rust_bits);
785	    let value_extern = f32::from_bits(value_extern_bits);
786	
787	    // Extract low 32 bits for offset comparison (shared space vs generic space)
788	    let rust_offset = rust_addr & 0xFFFF_FFFF;
789	    let extern_offset = extern_addr & 0xFFFF_FFFF;
790	
791	    println!("    Results:");
792	    println!(
793	        "      Rust smem addr:   0x{:x} (offset: 0x{:x}, mod 128 = {})",
794	        rust_addr, rust_offset, rust_align_mod
795	    );
796	    println!(
797	        "      Extern smem addr: 0x{:x} (offset: 0x{:x}, mod 128 = {})",
798	        extern_addr, extern_offset, extern_align_mod
799	    );
800	    println!("      Value via Rust:   {}", value_rust);
801	    println!("      Value via Extern: {}", value_extern);
802	
803	    // Check if offsets match (same shared memory location)
804	    let offsets_match = rust_offset == extern_offset;
805	
806	    // Check if values match (correctly shared)
807	    let values_match = (value_rust - 42.0).abs() < 0.001 && (value_extern - 42.0).abs() < 0.001;
808	
809	    // Check alignment - if linker took max, both should be 128B aligned
810	    let is_128_aligned = rust_align_mod == 0 && extern_align_mod == 0;
811	
812	    println!("    Analysis:");
813	    println!(
814	        "      Offsets match: {} (both at 0x{:x})",
815	        offsets_match, rust_offset
816	    );
817	    println!("      128B aligned:  {}", is_128_aligned);
818	    println!("      Values = 42.0: {}", values_match);
819	
820	    if offsets_match && values_match {
821	        println!("    ✓ PASSED (same shared memory, values correct)");
822	        *passed += 1;
823	    } else if offsets_match && !values_match {
824	        println!("    ⚠ PARTIAL: Same offset but values wrong!");
825	        println!("      → Rust/extern use different symbols that resolve to same offset");
826	        println!("      → But writes via one symbol don't appear via the other");
827	        *failed += 1;
828	    } else {
829	        println!("    ✗ FAILED");
830	        if !offsets_match {
831	            println!("      - Offsets don't match (different allocations)");
832	        }
833	        if !values_match {
834	            println!("      - Values don't match");
835	        }
836	        *failed += 1;
837	    }
838	}
